<?php
session_start(); include "includes/db.php"; include "includes/model.php"; requireLogin();
if(isset($_GET["delete"]) && currentUserCan("can_delete_stock")){mysqli_query($conn,"DELETE FROM products WHERE id=".intval($_GET["delete"]));header("Location:track_stock.php");exit();}
if(isset($_GET["sell"]) && currentUserCan("can_edit_stock")){mysqli_query($conn,"UPDATE products SET current_stock=GREATEST(current_stock-5,0) WHERE id=".intval($_GET["sell"]));header("Location:track_stock.php");exit();}
if(isset($_GET["add"]) && currentUserCan("can_edit_stock")){mysqli_query($conn,"UPDATE products SET current_stock=current_stock+10 WHERE id=".intval($_GET["add"]));header("Location:track_stock.php");exit();}
$r=mysqli_query($conn,"SELECT p.*, s.demand_index FROM products p JOIN store_profile s ON p.store_id=s.id ORDER BY days_to_expiry ASC");
?><!DOCTYPE html><html><head><title>Track Stock</title><link rel="stylesheet" href="assets/style.css"></head><body><div class="layout"><?php include "includes/sidebar.php"; ?><main class="main"><div class="page-title"><h1>Track Stock</h1><p>50-product inventory with live forecast, risk and access-controlled actions</p></div><div class="card table-wrap"><table><tr><th>Product</th><th>Category</th><th>Location</th><th>Stock</th><th>Forecast</th><th>Expiry</th><th>Risk</th><th>AI Action</th><th>Manage</th></tr>
<?php while($p=mysqli_fetch_assoc($r)){ $forecast=forecastDemand($p["base_daily_sales"],$p["category"],$p["demand_index"],$p["promotion_flag"],$p["days_to_expiry"]); $risk=riskLevel($p["current_stock"],$forecast,$p["days_to_expiry"]); $disc=discountValue($risk,$p["days_to_expiry"]); ?><tr><td><?= $p["product_name"] ?></td><td><?= $p["category"] ?></td><td><?= $p["location"] ?></td><td><?= $p["current_stock"] ?></td><td><?= $forecast ?></td><td><?= $p["days_to_expiry"] ?> days</td><td><span class="badge <?= strtolower($risk) ?>"><?= $risk ?></span></td><td><?= aiAction($risk,$disc) ?></td><td><?php if(currentUserCan("can_edit_stock")){ ?><a class="btn btn-light" href="?sell=<?= $p["id"] ?>">Sell 5</a><a class="btn btn-light" href="?add=<?= $p["id"] ?>">+10</a><?php } ?><?php if(currentUserCan("can_delete_stock")){ ?><a class="btn btn-danger" onclick="return confirm('Delete item?')" href="?delete=<?= $p["id"] ?>">Delete</a><?php } ?><?php if(!currentUserCan("can_edit_stock") && !currentUserCan("can_delete_stock")) echo "View only"; ?></td></tr><?php } ?></table></div></main></div></body></html>